Below is a **simple full example** of an Inventory Management System with:

- ✅ Node.js (Express) backend API  
- ✅ Stock deduction on purchase  
- ✅ Low stock logging (< 5)  
- ✅ Stock change history tracking  
- ✅ React dashboard to view stock + low-stock items  

---

# 🟢 Backend (Node.js + Express)

### 📁 Example Structure
```
backend/
  server.js
  controllers/
    inventoryController.js
  routes/
    inventoryRoutes.js
```

---

## 1️⃣ Install Dependencies

```bash
npm init -y
npm install express cors uuid
```

---

## 2️⃣ `server.js`

```js
const express = require("express");
const cors = require("cors");
const inventoryRoutes = require("./routes/inventoryRoutes");

const app = express();
app.use(cors());
app.use(express.json());

app.use("/api/inventory", inventoryRoutes);

const PORT = 5000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});
```

---

## 3️⃣ `routes/inventoryRoutes.js`

```js
const express = require("express");
const router = express.Router();
const inventoryController = require("../controllers/inventoryController");

router.get("/", inventoryController.getAllProducts);
router.post("/purchase", inventoryController.purchaseItem);
router.get("/low-stock", inventoryController.getLowStockItems);
router.get("/history", inventoryController.getStockHistory);

module.exports = router;
```

---

## 4️⃣ `controllers/inventoryController.js`

```js
const { v4: uuidv4 } = require("uuid");

// In-memory database (replace with real DB in production)
let products = [
  { id: "1", name: "Laptop", stock: 10 },
  { id: "2", name: "Phone", stock: 8 },
  { id: "3", name: "Headphones", stock: 4 },
];

let stockHistory = [];

// Get all products
exports.getAllProducts = (req, res) => {
  res.json(products);
};

// Purchase item
exports.purchaseItem = (req, res) => {
  const { productId, quantity } = req.body;

  const product = products.find(p => p.id === productId);

  if (!product) {
    return res.status(404).json({ message: "Product not found" });
  }

  if (product.stock < quantity) {
    return res.status(400).json({ message: "Not enough stock available" });
  }

  const previousStock = product.stock;
  product.stock -= quantity;

  // Log if stock is low
  if (product.stock < 5) {
    console.log(`⚠️ Low stock alert for ${product.name}. Current stock: ${product.stock}`);
  }

  // Save stock history
  stockHistory.push({
    id: uuidv4(),
    productId: product.id,
    productName: product.name,
    change: -quantity,
    previousStock,
    newStock: product.stock,
    timestamp: new Date()
  });

  res.json({
    message: "Purchase successful",
    product
  });
};

// Get low stock items
exports.getLowStockItems = (req, res) => {
  const lowStockItems = products.filter(p => p.stock < 5);
  res.json(lowStockItems);
};

// Get stock history
exports.getStockHistory = (req, res) => {
  res.json(stockHistory);
};
```

---

# 🟢 Frontend (React Dashboard)

---

## 1️⃣ Install Axios

```bash
npm install axios
```

---

## 2️⃣ `InventoryDashboard.js`

```jsx
import React, { useEffect, useState } from "react";
import axios from "axios";

const InventoryDashboard = () => {
  const [products, setProducts] = useState([]);
  const [lowStock, setLowStock] = useState([]);

  const fetchProducts = async () => {
    const res = await axios.get("http://localhost:5000/api/inventory");
    setProducts(res.data);
  };

  const fetchLowStock = async () => {
    const res = await axios.get("http://localhost:5000/api/inventory/low-stock");
    setLowStock(res.data);
  };

  useEffect(() => {
    fetchProducts();
    fetchLowStock();
  }, []);

  return (
    <div style={{ padding: "30px", fontFamily: "Arial" }}>
      <h1>Inventory Dashboard</h1>

      <h2>Current Stock Levels</h2>
      <table border="1" cellPadding="10" style={{ marginBottom: "30px" }}>
        <thead>
          <tr>
            <th>Product</th>
            <th>Stock</th>
          </tr>
        </thead>
        <tbody>
          {products.map(product => (
            <tr key={product.id}>
              <td>{product.name}</td>
              <td>{product.stock}</td>
            </tr>
          ))}
        </tbody>
      </table>

      <h2 style={{ color: "red" }}>Low Stock Items (Less than 5)</h2>
      {lowStock.length === 0 ? (
        <p>No low stock items 🎉</p>
      ) : (
        <ul>
          {lowStock.map(item => (
            <li key={item.id}>
              {item.name} — {item.stock} remaining
            </li>
          ))}
        </ul>
      )}
    </div>
  );
};

export default InventoryDashboard;
```

---

# 🔥 How It Works

### When a purchase happens:
1. Frontend sends:
```json
POST /api/inventory/purchase
{
  "productId": "1",
  "quantity": 2
}
```

2. Backend:
- Deducts stock
- Logs low stock if < 5
- Stores stock change in history array
- Returns updated product

---

# 🚀 Optional Improvements (For Production)

You would normally:

- Replace in-memory arrays with:
  - MongoDB
  - PostgreSQL
  - MySQL
- Add authentication
- Add pagination for history
- Use WebSockets for live stock updates
- Add admin controls for restocking

